import os


def getEncryptionKey(data, key):
    '''
    Create a static vector, cipher using AES and CBC mode
    encrypt the data using the cipher by padding up to the block_size, and return it
    '''
    if not isinstance(data, (bytes, bytearray)):
        raise TypeError()
    if not isinstance(key, (bytes, bytearray)):
        raise TypeError()

    if 'AES' not in globals() or not hasattr(AES, 'new') or not hasattr(AES, 'MODE_CBC') or not hasattr(AES, 'block_size'):
        raise RuntimeError()
    if 'pad' not in globals() or not callable(pad):
        raise RuntimeError()

    k = bytes(key)
    if len(k) not in (16, 24, 32):
        raise ValueError()

    iv = os.urandom(AES.block_size)
    try:
        cipher = AES.new(k, AES.MODE_CBC, iv)
        ct = cipher.encrypt(pad(bytes(data), AES.block_size))
    except Exception as e:
        raise RuntimeError() from e

    if not isinstance(ct, (bytes, bytearray)):
        raise RuntimeError()
    return iv + bytes(ct)

